import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"RTB House","description":"","frontmatter":{"title":"RTB House","slug":"rtb-house"},"headers":[],"relativePath":"marketer-hub/rtb-house.md","filePath":"marketer-hub/rtb-house.md"}'),n={name:"marketer-hub/rtb-house.md"};function i(s,t,d,l,h,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<p><em>[Image: 1328]</em>.png &quot;RTB House + branch.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="https://www.rtbhouse.com/" target="_blank" rel="noreferrer">RTB House Inc.</a> provides digital advertising technology services. The Company delivers digital advertising campaigns to customers who have displayed purchase intent. RTB House serves customers worldwide.</p><h3 id="partner-capabilities" tabindex="-1">Partner Capabilities <a class="header-anchor" href="#partner-capabilities" aria-label="Permalink to &quot;Partner Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Contact support at RTB House for more information</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>- Click-Through Attribution - View-Through Attribution</td></tr><tr><td>Ad Campaign Types</td><td>- Retargeting campaigns</td></tr><tr><td>Ad Formats</td><td>- Banner - Video</td></tr><tr><td>Click Types</td><td>- Server-side click</td></tr><tr><td>Supported Platforms</td><td>- iOS - Android - Windows - Mac OS - Unix</td></tr><tr><td>Link Wrapping</td><td>Supported</td></tr><tr><td>Cost Ingestion Support</td><td>Supported</td></tr><tr><td>Cost Ingestion Types</td><td>via API (Beta)</td></tr><tr><td>Cost Time Zone</td><td>GMT</td></tr><tr><td>Cost Data Scheduling</td><td>[ 4, 9, 12, 18, 24, 36, 48, 72, 96, 120, 240, 360, 480, 720 ] in hours from midnight</td></tr><tr><td>Pricing Models</td><td>- CPC - CPM - CPA</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable RTB House, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Performance <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Have the following enabled in RTB House:</p><ul><li>The account being used must not have multi-factor authentication enabled.</li><li>The feature <strong>SHOW_COUNTRY_COLUMN</strong> must be enabled in the API for your account</li><li>The account must have <code>campaign id</code> mapped in tracking links</li></ul></li><li><p>Running campaigns through RTB House.</p></li></ol><h2 id="enable-rtb-house" tabindex="-1">Enable RTB House <a class="header-anchor" href="#enable-rtb-house" aria-label="Permalink to &quot;Enable RTB House&quot;">​</a></h2><h3 id="_1-enable-rtb-house-in-branch" tabindex="-1">1. Enable RTB House in Branch <a class="header-anchor" href="#_1-enable-rtb-house-in-branch" aria-label="Permalink to &quot;1. Enable RTB House in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads</strong> &gt; <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for RTB House. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_rtb_house_sa?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>You&#39;ll need to input your Region.<br> For EMEA, enter <strong>emea</strong><br> For APAC, enter <strong>asia</strong><br> For Americas, enter <strong>us</strong><br> Please reach out to your RTB House Account Manager if you have any questions.</p><p>Click the <strong>Save &amp; Enable</strong> button.</p><p>.png &quot;RTB House enable.png&quot;)</p><h3 id="_2-configure-postbacks" tabindex="-1">2. Configure Postbacks <a class="header-anchor" href="#_2-configure-postbacks" aria-label="Permalink to &quot;2. Configure Postbacks&quot;">​</a></h3><p>Enabling RTB House will automatically enable the following postbacks:</p><ul><li>INSTALL</li></ul><p>.png &quot;rtb house postbacks.png&quot;)</p><p>You can configure these postbacks or add more under the <a href="https://dashboard.branch.io/ads/partner-management/a_rtb_house_sa?tab=postback" target="_blank" rel="noreferrer"><strong>Postback Config</strong></a> tab.</p><h4 id="send-all-events" tabindex="-1">Send All Events <a class="header-anchor" href="#send-all-events" aria-label="Permalink to &quot;Send All Events&quot;">​</a></h4><p>Optionally, you can check the checkbox for a given postback for sending all events. When checked, all events will be sent regardless of attribution. Otherwise, the postback will only fire for events attributed to RTB House.</p><h4 id="adding-postbacks" tabindex="-1">Adding Postbacks <a class="header-anchor" href="#adding-postbacks" aria-label="Permalink to &quot;Adding Postbacks&quot;">​</a></h4><p>Click the <strong>Add New Postback</strong> button at the bottom of the screen. A modal will appear that will allow you to select an event that you are tracking with the Branch SDKs (including Custom Events).</p><p>.gif &quot;Add New Postbacks.gif&quot;)</p><p>For more in-depth postback configurations, view our guides:</p><ul><li><a href="./basic-postback-configuration.html">Basic Postback Configuration</a></li><li><a href="./advanced-postback-configuration.html">Advanced Postback Configuration</a></li><li><strong>Recommended</strong> 👍 <a href="./testing-postbacks.html">Test Postbacks</a></li></ul><h3 id="_3-configure-attribution-windows" tabindex="-1">3. Configure Attribution Windows <a class="header-anchor" href="#_3-configure-attribution-windows" aria-label="Permalink to &quot;3. Configure Attribution Windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_rtb_house_sa?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows</strong></a> tab to set windows by attribution type.</p><h4 id="recommended-attribution-windows" tabindex="-1">Recommended Attribution Windows <a class="header-anchor" href="#recommended-attribution-windows" aria-label="Permalink to &quot;Recommended Attribution Windows&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Attribution Type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>90 days</td></tr><tr><td>click to install</td><td>30 days</td></tr><tr><td>click to conversion event</td><td>90 days</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event.</td><td>1 day</td></tr></tbody></table><h3 id="_4-set-up-cost-data" tabindex="-1">4. Set up Cost Data <a class="header-anchor" href="#_4-set-up-cost-data" aria-label="Permalink to &quot;4. Set up Cost Data&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Beta for Non-SANs</p><p>Cost Data for Non-Self-Attributing Networks (Non-SANs) is a feature currently in Beta; be aware that there may be unexpected bugs/behaviors until the full release.</p></div><p>To set up cost ingestion for RTB House, you will need to authenticate using your <strong>User Name and Password</strong>. Please reach out to your RTB House account manager if you have trouble finding these values.</p><p>Enter your <strong>User Name and Password</strong>, and click <strong>Save Authentication</strong></p><p>.png)</p><h3 id="_5-create-branch-ad-link" tabindex="-1">5. Create Branch Ad Link <a class="header-anchor" href="#_5-create-branch-ad-link" aria-label="Permalink to &quot;5. Create Branch Ad Link&quot;">​</a></h3><p>Next, you&#39;ll need to create a Branch Ad Link for your RTB House campaigns in order for Branch to properly attribute conversions.</p><p>[.png)</p><p>help.branch.io</p><p>Create Ad Links](/docs/ad-links)</p><p>The Branch Ad Link you create will be placed in your RTB House campaign.</p><h3 id="_6-verify-data-in-branch" tabindex="-1">6. Verify Data in Branch <a class="header-anchor" href="#_6-verify-data-in-branch" aria-label="Permalink to &quot;6. Verify Data in Branch&quot;">​</a></h3><p>After launching your RTB House campaigns, and conversions begin to happen, you&#39;ll want to verify data is being sent from Branch to RTB House. You can look at the <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Branch Dashboard&#39;s Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad partner (3p)</td><td>equals</td><td><code>a_rtb_house_sa</code></td></tr></tbody></table><p>Once applied, data should flow through the Liveview, and you can see the data being sent to RTB House from Branch.</p><h4 id="verifying-cost-data" tabindex="-1">Verifying Cost Data <a class="header-anchor" href="#verifying-cost-data" aria-label="Permalink to &quot;Verifying Cost Data&quot;">​</a></h4><p>To verify that cost data is flowing into Branch, you need to have the following:</p><ul><li>Completed all implementation steps above</li><li>You need to already be live with campaigns running for the ad network</li><li>Wait 24 hours for data to be pulled in</li></ul>',48)])])}const b=e(n,[["render",i]]);export{p as __pageData,b as default};
